    sts_args+=(--tags "${AWS_ASSUME_ROLE_TAGS_JSON}")
  fi
  if [[ -n "${AWS_ASSUME_ROLE_TRANSITIVE_TAG_KEYS:-}" ]]; then
    IFS=',' read -r -a _ttk <<<"${AWS_ASSUME_ROLE_TRANSITIVE_TAG_KEYS}"
    sts_args+=(--transitive-tag-keys "${_ttk[@]}")
