    local w_args=(sts assume-role-with-web-identity --role-arn "${AWS_ROLE_ARN}" --role-session-name "${AWS_ROLE_SESSION_NAME}" --duration-seconds "${AWS_ASSUME_ROLE_DURATION_SECONDS}" --web-identity-token "${token}")
