  log "S3 sync: ${ARTIFACT_PATH} -> ${dest}"
  run aws_cli s3 sync "${ARTIFACT_PATH}" "${dest}" --only-show-errors
}

s3_upload() {
  require_env S3_BUCKET ARTIFACT_PATH
  [[ -f "${ARTIFACT_PATH}" ]] || die "ARTIFACT_PATH must be a file for s3-upload: ${ARTIFACT_PATH}"
