    run aws_cli cloudformation wait stack-update-complete --stack-name "${STACK_NAME}" || \
    run aws_cli cloudformation wait stack-create-complete --stack-name "${STACK_NAME}"
  fi
}

cf_changeset() {
  require_env STACK_NAME TEMPLATE_FILE
  [[ -f "${TEMPLATE_FILE}" ]] || die "TEMPLATE_FILE not found: ${TEMPLATE_FILE}"
  if [[ -z "${CHANGESET_NAME:-}" ]]; then
    CHANGESET_NAME="changeset-$(date +%Y%m%d%H%M%S)"
  fi
  log "CloudFormation create changeset: stack=${STACK_NAME} changeset=${CHANGESET_NAME}"
  local -a args
  IFS=$'\0' read -r -d '' -a args < <(cf_common_args && printf '\0')

  local change_type="UPDATE"
  if ! aws_cli cloudformation describe-stacks --stack-name "${STACK_NAME}" >/dev/null 2>&1; then
    change_type="CREATE"
  fi

  run aws_cli cloudformation create-change-set \
    --stack-name "${STACK_NAME}" \
    --change-set-name "${CHANGESET_NAME}" \
    --change-set-type "${change_type}" \
    --template-body "file://${TEMPLATE_FILE}" \
    --capabilities ${CAPABILITIES} \
    ${PARAMETERS_FILE:+--parameters "file://${PARAMETERS_FILE}"}

  if is_true "${WAIT}"; then
    run aws_cli cloudformation wait change-set-create-complete --stack-name "${STACK_NAME}" --change-set-name "${CHANGESET_NAME}" || true
